pub fn evaluate(mode: PolicyMode, pressure: u8, _action: &str) -> Verdict {
    match mode {
        PolicyMode::Observe  => Verdict::Allow,
        PolicyMode::Safe     => {
            if pressure >= 90 { Verdict::Quarantine }
            else { Verdict::Allow }
        }
        PolicyMode::Guardian => {
            if pressure >= 80 { Verdict::Deny }
            else if pressure >= 60 { Verdict::Quarantine }
            else { Verdict::Allow }
        }
        PolicyMode::Lockdown => Verdict::Deny,
    }
}
