#define GGUF_MAGIC 0x46554747u
#define GGUF_V3    3u

typedef struct {
    uint32_t magic;
    uint32_t version;
    uint64_t tensor_count;
    uint64_t kv_count;
} GGUFHeader;

EFI_STATUS gguf_read_header(EFI_FILE_PROTOCOL *f, GGUFHeader *out) {
    UINTN sz = sizeof(GGUFHeader);
    EFI_STATUS st = f->Read(f, &sz, out);
    if (EFI_ERROR(st) || sz != sizeof(GGUFHeader)) return EFI_INVALID_PARAMETER;
    if (out->magic   != GGUF_MAGIC) return EFI_UNSUPPORTED;
    if (out->version  < 2 || out->version > GGUF_V3) return EFI_INCOMPATIBLE_VERSION;
    return EFI_SUCCESS;
}
