typedef struct { uint8_t *base; uint8_t *next; uint8_t *end; } Zone;

void zone_init(Zone *z, void *base, size_t size) {
    z->base = z->next = (uint8_t *)base;
    z->end  = (uint8_t *)base + size;
}

void *zone_alloc(Zone *z, size_t size) {
    size = (size + 15u) & ~15u;  // 16-byte align
    if (z->next + size > z->end) return NULL;
    void *ptr = z->next;
    z->next += size;
    return ptr;
}

size_t zone_used(const Zone *z)       { return (size_t)(z->next - z->base); }
size_t zone_free_bytes(const Zone *z) { return (size_t)(z->end  - z->next); }
