// Single Mamba step, dimension d_state
void mamba_step(
    int d,               // state dimension
    const float *A,      // [d] diagonal A (exponentiated)
    const float *B,      // [d] B projection of current token
    const float *C,      // [d] C projection (output)
    float        D_val,  // scalar skip connection
    float        x_t,    // current input (scalar per head)
    float       *h,      // [d] hidden state (in/out)
    float       *y_out   // output scalar
) {
    float y = D_val * x_t;
    for (int i = 0; i < d; i++) {
        h[i] = A[i] * h[i] + B[i] * x_t;
        y   += C[i] * h[i];
    }
    *y_out = y;
}
