#define COM1_PORT 0x3F8u

static inline void serial_init_com1(void) {
    IoWrite8(COM1_PORT + 1, 0x00);  // disable interrupts
    IoWrite8(COM1_PORT + 3, 0x80);  // DLAB on
    IoWrite8(COM1_PORT + 0, 0x03);  // 38400 baud (divisor lo)
    IoWrite8(COM1_PORT + 1, 0x00);  // divisor hi
    IoWrite8(COM1_PORT + 3, 0x03);  // 8N1
    IoWrite8(COM1_PORT + 2, 0xC7);  // FIFO enable
    IoWrite8(COM1_PORT + 4, 0x0B);  // RTS+DTR
}

static inline void serial_putc(char c) {
    while (!(IoRead8(COM1_PORT + 5) & 0x20));  // wait TX empty
    IoWrite8(COM1_PORT, (UINT8)c);
}

void print_serial(const char *s) {
    for (; *s; s++) {
        if (*s == '\n') serial_putc('\r');
        serial_putc(*s);
    }
}
