EFI_STATUS open_esp_file(EFI_HANDLE image,
                          const CHAR16 *path,
                          EFI_FILE_PROTOCOL **out) {
    EFI_LOADED_IMAGE_PROTOCOL       *li = NULL;
    EFI_SIMPLE_FILE_SYSTEM_PROTOCOL *fs = NULL;
    EFI_FILE_PROTOCOL               *root = NULL;
    EFI_STATUS st;

    st = BS->HandleProtocol(image, &gEfiLoadedImageProtocolGuid, (void**)&li);
    if (EFI_ERROR(st)) return st;

    st = BS->HandleProtocol(li->DeviceHandle,
                            &gEfiSimpleFileSystemProtocolGuid, (void**)&fs);
    if (EFI_ERROR(st)) return st;

    st = fs->OpenVolume(fs, &root);
    if (EFI_ERROR(st)) return st;

    st = root->Open(root, out, (CHAR16*)path, EFI_FILE_MODE_READ, 0);
    root->Close(root);
    return st;
}
