pub struct SwarmNodeSpec { pub id: String, pub uart_path: PathBuf }

pub fn parse_node_specs(spec: &str) -> Result<Vec<SwarmNodeSpec>, String> {
    spec.split(',')
        .map(|s| s.trim())
        .filter(|s| !s.is_empty())
        .map(|s| {
            let (id, path) = s.split_once(':')
                .ok_or_else(|| format!("invalid node spec: {s}"))?;
            Ok(SwarmNodeSpec {
                id: id.to_string(),
                uart_path: PathBuf::from(path),
            })
        })
        .collect()
}
